const response = $json.choices?.[0]?.message?.content || '{}';
let examRequest;
try {
  examRequest = JSON.parse(response);
} catch (e) {
  throw new Error('Invalid JSON response from OpenAI');
}

if (!Array.isArray(examRequest.exams) || !examRequest.priority) {
  throw new Error('Missing required fields in exam request');
}

examRequest.generatedAt = new Date().toISOString();
examRequest.patientId = $json.body.patientId || null;

return [{ json: examRequest }];
